description.text:
### Tested versions

Reproducible in 4.4

### System information

Godot v4.4.stable.mono - Ubuntu 24.04.1 LTS 24.04 on X11 - X11 display driver, Multi-window, 2 monitors - Vulkan (Forward+) - integrated AMD Radeon Graphics (RADV RENOIR) - AMD Ryzen 7 5700G with Radeon Graphics (16 threads)

### Issue description

Godot keeps crashing silently when I compile by scripts when a voxel chunk is generated

here is the code for the whole project...
```cs
using Godot;
using System;
using System.Collections.Generic;
using System.Numerics;
using System.Threading;
using System.Threading.Tasks;
using Godot.Collections;
using Vector2 = Godot.Vector2;
using Vector3 = Godot.Vector3;

[Tool][GlobalClass]
public partial class VoxelWorld : Node3D
{
    [ExportToolButton("Clear Chunks")]
    private Callable CallClearChunks => Callable.From(ClearChunks);
    [ExportToolButton("Generate Chunks")]
    private Callable CallGenerateChunks => Callable.From(GenerateChunks);

    [Export] public int ChunkSize  { get; set; } = 16;
    [Export] public int WorldSize  { get; set; } = 1;

    [Export] public int   NoiseSeed       { get; set; } = 1;
    [Export] public float NoiseFrequency  { get; set; } = 1;
    [Export] public float NoiseThreshold  { get; set; } = 0;

    [Export] public Vector2 TextureScale { get; set; } = new(0.25f, 0.5f);
    [Export] public StandardMaterial3D? Material { get; set; }

    private  void  ClearChunks()
    {
        foreach (var item in GetChildren())
            if (item is VoxelChunk chunk)
                chunk.Free();
    }

    private async void GenerateChunks()
    {
        _noise.Seed      = NoiseSeed;
        //_noise.NoiseType = FastNoiseLite.NoiseTypeEnum.Cellular;
        _noise.SetFrequency(NoiseFrequency);

        ClearChunks();
        for (var x = 0; x < WorldSize; x++)
        for (var y = 0; y < WorldSize; y++)
        for (var z = 0; z < WorldSize; z++)
        {
            GenerateChunk(new Vector3I(x, y, z), TextureScale);
            await ToSignal(GetTree(), SceneTree.SignalName.ProcessFrame);
        }
    }

    private void GenerateChunk(Vector3I chunkIndex, Vector2 textureScale)
    {
        var chunk = new VoxelChunk(ChunkSize, chunkIndex, textureScale, Material);
        _chunks[chunkIndex] = chunk;
        AddChild(chunk);
        chunk.Update();
    }

    public BlockType GetBlock(Vector3 position)
    {
        var sample = _noise.GetNoise3D(position.X, position.Y, position.Z);
        //GD.Print(sample);
        if (sample > -NoiseThreshold)
        {
            return BlockType.Air;
        }
        return BlockType.Dirt;
    }

    private FastNoiseLite _noise = new();
    private readonly System.Collections.Generic.Dictionary<Vector3I, VoxelChunk> _chunks = new();
}

```

```cs
using Godot;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Numerics;
using Godot.Collections;
using Array = Godot.Collections.Array;
using Vector2 = Godot.Vector2;
using Vector3 = Godot.Vector3;



[Tool]
public partial class VoxelChunk : MeshInstance3D
{
    public int                 ChunkSize    { get; set; }
    public Vector3I            ChunkIndex   { get; set; }
    public Vector2             TextureScale { get; set; }
    public StandardMaterial3D? Material     { get; set; }

    public VoxelChunk(int chunkSize, Vector3I chunkIndex, Vector2 textureScale, StandardMaterial3D? material)
    {
        ChunkSize    = chunkSize;
        ChunkIndex   = chunkIndex;
        TextureScale = textureScale;
        Material     = material;
        Position  = ChunkIndex * ChunkSize;
    }


    private void GenerateCube   (Vector3I blockIndex)
    {
        var cubePosition= blockIndex;
        var cubeUvScale = TextureScale;

        // Up face
        if (IsBlockAir(blockIndex + Vector3I.Up))
        {
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, 0.5f, -0.5f));
            _tool.AddVertex(cubePosition + new Vector3(0.5f, 0.5f, -0.5f));
            _tool.AddVertex(cubePosition + new Vector3(0.5f, 0.5f, 0.5f));
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, 0.5f, 0.5f));
            _tool.AddQuadUvs(0, 0, cubeUvScale);
            _tool.AddQuadIndices();
        }

        // East face
        if (IsBlockAir(blockIndex + Vector3I.Right))
        {
            _tool.AddVertex(cubePosition + new Vector3(0.5f, 0.5f, 0.5f));
            _tool.AddVertex(cubePosition + new Vector3(0.5f, 0.5f, -0.5f));
            _tool.AddVertex(cubePosition + new Vector3(0.5f, -0.5f, -0.5f));
            _tool.AddVertex(cubePosition + new Vector3(0.5f, -0.5f, 0.5f));
            _tool.AddQuadUvs(3, 0, cubeUvScale);
            _tool.AddQuadIndices();
        }

        // South face
        if (IsBlockAir(blockIndex + Vector3I.Back))
        {
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, 0.5f, 0.5f));
            _tool.AddVertex(cubePosition + new Vector3(0.5f, 0.5f, 0.5f));
            _tool.AddVertex(cubePosition + new Vector3(0.5f, -0.5f, 0.5f));
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, -0.5f, 0.5f));
            _tool.AddQuadUvs(0, 1, cubeUvScale);
            _tool.AddQuadIndices();
        }

        // West face
        if (IsBlockAir(blockIndex + Vector3I.Left))
        {
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, 0.5f, -0.5f));
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, 0.5f, 0.5f));
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, -0.5f, 0.5f));
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, -0.5f, -0.5f));
            _tool.AddQuadUvs(1, 1, cubeUvScale);
            _tool.AddQuadIndices();
        }

        // North face
        if (IsBlockAir(blockIndex + Vector3I.Forward))
        {
            _tool.AddVertex(cubePosition + new Vector3(0.5f, 0.5f, -0.5f));
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, 0.5f, -0.5f));
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, -0.5f, -0.5f));
            _tool.AddVertex(cubePosition + new Vector3(0.5f, -0.5f, -0.5f));
            _tool.AddQuadUvs(2, 0, cubeUvScale);
            _tool.AddQuadIndices();
        }

        // Bottom face
        if (IsBlockAir(blockIndex + Vector3I.Down))
        {
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, -0.5f, 0.5f));
            _tool.AddVertex(cubePosition + new Vector3(0.5f, -0.5f, 0.5f));
            _tool.AddVertex(cubePosition + new Vector3(0.5f, -0.5f, -0.5f));
            _tool.AddVertex(cubePosition + new Vector3(-0.5f, -0.5f, -0.5f));
            _tool.AddQuadUvs(1, 0, cubeUvScale);
            _tool.AddQuadIndices();
        }
    }
    private void GenerateChunk  ()
    {
        _tool.Reset();

        for (var x = 0; x < ChunkSize; x++)
        for (var y = 0; y < ChunkSize; y++) 
        for (var z = 0; z < ChunkSize; z++) 
        {
            if (_blocks[x,y,z] == BlockType.Air)
                continue;

            GenerateCube(new Vector3I(x, y, z));
        }

        Mesh = _tool.Commit(Material);
    }
    private void InitializeChunk()
    {
        _blocks = new BlockType[ChunkSize, ChunkSize, ChunkSize];
        for (var x = 0; x < ChunkSize; x++)
        for (var y = 0; y < ChunkSize; y++)
        for (var z = 0; z < ChunkSize; z++)
        {
            var parent = GetParent<VoxelWorld>();
            if (parent == null) return;
            var index = new Vector3I(x, y, z);
            GD.Print(GetBlockPosition(index));
            var block = parent.GetBlock(GetBlockPosition(index));
            SetBlock(index, block);
        }
    }

    public bool  IsBlockAir(Vector3I blockIndex)
    {
        if (blockIndex.X < 0 || blockIndex.Y < 0 || blockIndex.Z < 0)
            return true;

        if (blockIndex.X >= ChunkSize || blockIndex.Y >= ChunkSize || blockIndex.Z >= ChunkSize)
            return true;

        if (_blocks[(int)blockIndex.X, (int)blockIndex.Y, (int)blockIndex.Z] == BlockType.Air)
            return true;

        return false;
    }

    public void      SetBlock        (Vector3I blockIndex, BlockType blockType)
    {
        _blocks[(int)blockIndex.X, (int)blockIndex.Y, (int)blockIndex.Z] = blockType;
    }
    public BlockType GetBlock        (Vector3I blockIndex)
    {
        return _blocks[(int)blockIndex.X, (int)blockIndex.Y, (int)blockIndex.Z];
    }

    public Vector3   GetBlockPosition(Vector3I blockIndex)
    {
        return GetBlockPosition(blockIndex.X, blockIndex.Y, blockIndex.Z);
    }
    public Vector3   GetBlockPosition(int blockIndexX, int blockIndexY, int blockIndexZ)
    {
        return Position + new Vector3I(blockIndexX, blockIndexY, blockIndexZ);
    }

    public void Update()
    {
        InitializeChunk();
        GenerateChunk();
    }

    private BlockType[,,]     _blocks = new BlockType[0,0,0];
    private readonly MeshTool _tool = new();

    public VoxelChunk()
    {
    }

    private sealed class MeshTool()
    {
        private List<Vector3 > Vertices { get; } = new();
        private List<int     > Indices  { get; } = new();
        private List<Vector2 > UVs      { get; } = new();

        private int FaceCount { get; set;  } = 0;

        public void Reset()
        {
            Vertices.Clear();
            Indices.Clear();
            UVs.Clear();
            FaceCount = 0;
        }

        public void AddVertex(Vector3 vertex)
        {
            Vertices.Add(vertex);
        }

        public void AddIndex(int index)
        {
            Indices.Add(index);
        }
        public void AddUv(Vector2 uv)
        {
            UVs.Add(uv);
        }
        public void AddQuadIndices()
        {
            AddIndex(FaceCount * 4 + 0);
            AddIndex(FaceCount * 4 + 1);
            AddIndex(FaceCount * 4 + 2);
            AddIndex(FaceCount * 4 + 0);
            AddIndex(FaceCount * 4 + 2);
            AddIndex(FaceCount * 4 + 3);
            FaceCount++;
        }
        public void AddQuadUvs    (int x, int y, Vector2 textureScale)
        {
            var a = new Vector2(textureScale.X * x                 , textureScale.Y * y                 );
            var b = new Vector2(textureScale.X * x + textureScale.X, textureScale.Y * y + textureScale.Y);

            AddUv(new Vector2(a.X,a.Y));
            AddUv(new Vector2(b.X,a.Y));
            AddUv(new Vector2(b.X,b.Y));
            AddUv(new Vector2(a.X,b.Y));
        }

        public Mesh Commit(StandardMaterial3D? material)
        {
            var meshData = new Array();
            meshData.Resize((int)Mesh.ArrayType.Max);
            meshData[(int)Mesh.ArrayType.Vertex] = Vertices.ToArray();
            meshData[(int)Mesh.ArrayType.Index ] = Indices .ToArray();
            meshData[(int)Mesh.ArrayType.TexUV ] = UVs     .ToArray();

            var mesh = new ArrayMesh();
            mesh.AddSurfaceFromArrays(Mesh.PrimitiveType.Triangles, meshData);
            mesh.SurfaceSetMaterial(0, material);
            return mesh;

        }
    }
}


public enum BlockType
{
    Dirt,
    Air
}
```

### Steps to reproduce

- Copy the code and paste it into a new project or download the project that I linked.
- Compile it.
- Create a VoxelWorld node.
- Setup properties (use world size of 1 and chunk size of 8)
- Click Generate in inspector
- After the world is generated, without clearing the world, edit one of the C# scripts and recompile the C# scripts by clicking on the hammer icon.
- Do it a few times you will get a silent crash

